import org.junit.Assert;

public class ReachingDefinitionsTest {
  @Test
  public void simpleLinear() {
    Program p = new SimpleProgramBuilder().emitWrite("x").emitWrite("x").buildProgram();
    AnalysisResult<Set<WriteInstruction>> result = p.analyze(new ReachingDefinitionsAnalyzer());
    Assert.assertEquals("0: write x [0: write x]\n1: write x [1: write x]\n2: end [1: write x]\n", result.toString());
  }
  @Test
  public void cycle() {
    Program p = new SimpleProgramBuilder().emitWrite("x").emitWrite("y").emitIfJump(0).buildProgram();
    AnalysisResult<Set<WriteInstruction>> result = p.analyze(new ReachingDefinitionsAnalyzer());
    Assert.assertEquals("0: write x [0: write x, 1: write y]\n1: write y [0: write x, 1: write y]\n2: ifjump 0 [0: write x, 1: write y]\n3: end [0: write x, 1: write y]\n", result.toString());
  }
}
